using Microsoft.AspNetCore.Mvc;
using WebAPI.Application.Interfaces;
using WebAPI.Application.Validators;


namespace WebAPI.Controllers;

using WebAPI.Domain;
using WebAPI.Application;

[ApiController]
[Route("api/[controller]")]


public class AuthController : ControllerBase
{
    private readonly IUserRepository userRepository_;
    private readonly IPasswordHasher passwordHasher_;
    private readonly ITokenService tokenService_;


    public AuthController(IUserRepository userRepository, IPasswordHasher passwordHasher, ITokenService tokenService)
    {
        userRepository_ = userRepository;
        passwordHasher_ = passwordHasher;
        tokenService_ = tokenService;
    }


    [HttpPost("register")]

    public async Task<ActionResult<UserDTO>> Register(CreateUserDTO dto)
    {
        var user =  new User
        {
            Username = dto.Username,
            Email = dto.Email,
            PasswordHash = passwordHasher_.Hash(dto.Password)
        };

        await userRepository_.AddAsync(user);
        return Ok(user.ToDTO());

    }

    [HttpPost("login")]

    public async Task<ActionResult<AuthResponseDTO>> Login(LoginDTO dto)
    {
        var allUsers_ = await userRepository_.GetAllAsync();
        var user_ = allUsers_.FirstOrDefault(u => u.Email == dto.Email);

        if (user_ == null || !passwordHasher_.Verify(dto.Password, user_.PasswordHash))
            return Unauthorized("Invalid email or password");

        var token_ = tokenService_.GenerateToken(user_);
        return Ok(new AuthResponseDTO { Token = token_, Username = user_.Username });
    }




}

using Microsoft.AspNetCore.Mvc;
using WebAPI.Application.Interfaces;
using WebAPI.Application.Validators;


namespace WebAPI.Controllers;

using WebAPI.Domain;
using WebAPI.Application;

[ApiController]
[Route("api/[controller]")]


public class AuthController : ControllerBase
{
    private readonly IUserRepository userRepository_;
    private readonly IPasswordHasher passwordHasher_;
    private readonly ITokenService tokenService_;


    public AuthController(IUserRepository userRepository, IPasswordHasher passwordHasher, ITokenService tokenService)
    {
        userRepository_ = userRepository;
        passwordHasher_ = passwordHasher;
        tokenService_ = tokenService;
    }


    [HttpPost("register")]

    public async Task<ActionResult<UserDTO>> Register(CreateUserDTO dto)
    {
        var user =  new User
        {
            Username = dto.Username,
            Email = dto.Email,
            PasswordHash = passwordHasher_.Hash(dto.Password)
        };

        await userRepository_.AddAsync(user);
        return Ok(user.ToDTO());

    }

    [HttpPost("login")]

    public async Task<ActionResult<AuthResponseDTO>> Login(LoginDTO dto)
    {
        var allUsers_ = await userRepository_.GetAllAsync();
        var user_ = allUsers_.FirstOrDefault(u => u.Email == dto.Email);

        // Verify expects (hash, password) per IPasswordHasher interface
        if (user_ == null || !passwordHasher_.Verify(user_.PasswordHash, dto.Password))
            return Unauthorized("Invalid email or password");

        var token_ = tokenService_.GenerateToken(user_);
        return Ok(new AuthResponseDTO { Token = token_, Username = user_.Username });
    }
    
    


}

using System.Text;
using FluentValidation;
using FluentValidation.AspNetCore;
using Microsoft.AspNetCore.Authentication.JwtBearer;
using Microsoft.EntityFrameworkCore;
using Microsoft.IdentityModel.Tokens;
using Microsoft.OpenApi;
using WebAPI.Application;
using WebAPI.Application.Interfaces;
using WebAPI.Application.Validators;
using WebAPI.Domain;
using WebAPI.Infrastructure;




var builder = WebApplication.CreateBuilder(args);

builder.Services.AddControllers();
builder.Services.AddEndpointsApiExplorer();
builder.Services.AddSwaggerGen(); // swagger 

builder.Services.AddSwaggerGen(options =>
{
    options.AddSecurityDefinition("Bearer", new OpenApiSecurityScheme
    {
        Name = "Authorization",
        Type = SecuritySchemeType.ApiKey,
        Scheme = "Bearer",
        BearerFormat = "JWT",
        In = ParameterLocation.Header,
        Description = "JWT Authorization header using the Bearer scheme."
    });

    options.AddSecurityRequirement(document => new OpenApiSecurityRequirement
    {
        [new OpenApiSecuritySchemeReference("Bearer", document)] = []
    });


});


// database  
builder.Services.AddDbContext<ApplicationDbContext>(options => 
    options.UseSqlite(builder.Configuration.GetConnectionString("DefaultConnection")));


builder.Services.AddScoped<IProductRepository, ProductRepository>();
builder.Services.AddScoped<IUserRepository, UserRepository>();
builder.Services.AddScoped<IUserProductRepository, UserProductRepository>();

builder.Services.AddScoped<ITokenService, TokenService>();



// fluent validation 
builder.Services.AddFluentValidationAutoValidation();
builder.Services.AddValidatorsFromAssemblyContaining<CreateProductDTOValidator>();
builder.Services.AddValidatorsFromAssemblyContaining<UpdateProductDTOValidator>();
builder.Services.AddValidatorsFromAssemblyContaining<CreateUserDTOValidator>();
builder.Services.AddValidatorsFromAssemblyContaining<UpdateUserDTOValidator>();
builder.Services.AddValidatorsFromAssemblyContaining<AssignProductToUserDTOValidator>();
builder.Services.AddValidatorsFromAssemblyContaining<ChangePasswordDTOValidator>();


// JWT auth

var jwtSettings_ = builder.Configuration.GetSection("Jwt");
builder.Services.AddAuthentication(JwtBearerDefaults.AuthenticationScheme)
    .AddJwtBearer(options =>
    {
        options.TokenValidationParameters = new TokenValidationParameters
        {
            ValidateIssuer = true,
            ValidateAudience = true,
            ValidateLifetime = true,
            ValidateIssuerSigningKey = true,
            ValidIssuer = jwtSettings_["Issuer"],
            ValidAudience = jwtSettings_["Audience"],
            IssuerSigningKey = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(jwtSettings_["Key"]!))
        };
    });

builder.Services.AddAuthorization();

builder.Services.AddOpenApi();

var app = builder.Build();

// Configure the HTTP request pipeline.
if (app.Environment.IsDevelopment())
{
    app.UseSwagger();
    app.UseSwaggerUI();
    app.MapOpenApi();
}

app.UseHttpsRedirection();

app.UseAuthentication();
app.UseAuthorization();

app.MapControllers();
app.UseAuthorization();
app.Run();

using System.Text;
using FluentValidation;
using FluentValidation.AspNetCore;
using Microsoft.AspNetCore.Authentication.JwtBearer;
using Microsoft.EntityFrameworkCore;
using Microsoft.IdentityModel.Tokens;
using Microsoft.OpenApi;
using WebAPI.Application;
using WebAPI.Application.Interfaces;
using WebAPI.Application.Validators;
using WebAPI.Domain;
using WebAPI.Infrastructure;




var builder = WebApplication.CreateBuilder(args);

builder.Services.AddControllers();
builder.Services.AddEndpointsApiExplorer();
builder.Services.AddSwaggerGen(); // swagger 

builder.Services.AddSwaggerGen(options =>
{
    options.AddSecurityDefinition("Bearer", new OpenApiSecurityScheme
    {
        Name = "Authorization",
        Type = SecuritySchemeType.ApiKey,
        Scheme = "Bearer",
        BearerFormat = "JWT",
        In = ParameterLocation.Header,
        Description = "JWT Authorization header using the Bearer scheme."
    });
    
    options.AddSecurityRequirement(document => new OpenApiSecurityRequirement
    {
        [new OpenApiSecuritySchemeReference("Bearer", document)] = []
    });
  

});


// database  
builder.Services.AddDbContext<ApplicationDbContext>(options => 
    options.UseSqlite(builder.Configuration.GetConnectionString("DefaultConnection")));


builder.Services.AddScoped<IProductRepository, ProductRepository>();
builder.Services.AddScoped<IUserRepository, UserRepository>();
builder.Services.AddScoped<IUserProductRepository, UserProductRepository>();

builder.Services.AddScoped<ITokenService, TokenService>();
// password hasher implementation
builder.Services.AddScoped<IPasswordHasher, Pbkdf2PasswordHasher>();



// fluent validation 
builder.Services.AddFluentValidationAutoValidation();
builder.Services.AddValidatorsFromAssemblyContaining<CreateProductDTOValidator>();
builder.Services.AddValidatorsFromAssemblyContaining<UpdateProductDTOValidator>();
builder.Services.AddValidatorsFromAssemblyContaining<CreateUserDTOValidator>();
builder.Services.AddValidatorsFromAssemblyContaining<UpdateUserDTOValidator>();
builder.Services.AddValidatorsFromAssemblyContaining<AssignProductToUserDTOValidator>();
builder.Services.AddValidatorsFromAssemblyContaining<ChangePasswordDTOValidator>();


// JWT auth

var jwtSettings_ = builder.Configuration.GetSection("Jwt");
builder.Services.AddAuthentication(JwtBearerDefaults.AuthenticationScheme)
    .AddJwtBearer(options =>
    {
        options.TokenValidationParameters = new TokenValidationParameters
        {
            ValidateIssuer = true,
            ValidateAudience = true,
            ValidateLifetime = true,
            ValidateIssuerSigningKey = true,
            ValidIssuer = jwtSettings_["Issuer"],
            ValidAudience = jwtSettings_["Audience"],
            IssuerSigningKey = new SymmetricSecurityKey(Encoding.UTF8.GetBytes(jwtSettings_["Key"]!))
        };
    });

builder.Services.AddAuthorization();

builder.Services.AddOpenApi();

var app = builder.Build();

// Configure the HTTP request pipeline.
if (app.Environment.IsDevelopment())
{
    app.UseSwagger();
    app.UseSwaggerUI();
    app.MapOpenApi();
}

app.UseHttpsRedirection();

app.UseAuthentication();
app.UseAuthorization();

app.MapControllers();
app.UseAuthorization();
app.Run();
